function sanitizeLegacyAuthText(value) {
  if (typeof value !== "string" || !value) return value;
  return value
    .replace(/授权浏览器已尝试启动，但还没有建立自动采集通道：[^。]+。如果没有弹出 Chrome\/Edge 窗口，请先关闭残留授权窗口后重新点击打开授权浏览器。/g, "当前网页调试模式没有平台采集页，请使用桌面版客户端测试自动采集。")
    .replace(/授权浏览器已尝试启动，但本机调试端口暂未就绪：[^。]+。请先在弹出的 Chrome 窗口完成登录；如稍后检测仍失败，可使用手动 Cookie 绑定。/g, "当前网页调试模式没有平台授权页面，请使用桌面版客户端完成登录授权。")
    .replace(/没有可用于 ([^ ]+) 的启用回复账号，请先在回复账号池添加账号并打开授权浏览器。/g, "没有可用于 $1 的启用回复账号，请先在回复账号池添加账号并完成一键登录授权。")
    .replace(/等待浏览器授权/g, "平台采集页未连接")
    .replace(/需检查授权浏览器/g, "平台采集页未连接")
    .replace(/打开账号授权浏览器/g, "打开账号登录窗口")
    .replace(/URL采集打开授权浏览器/g, "作品采集打开登录窗口")
    .replace(/URL采集打开登录窗口/g, "作品采集打开登录窗口")
    .replace(/URL可见采集/g, "作品可见采集")
    .replace(/URL可见评论/g, "作品可见评论")
    .replace(/URL 可见采集/g, "作品页可见采集")
    .replace(/URL 可见评论/g, "作品页可见评论")
    .replace(/目标 URL/g, "目标页面")
    .replace(/URL 任务/g, "作品任务")
    .replace(/浏览器授权登录态/g, "登录窗口授权登录态")
    .replace(/授权浏览器中的/g, "平台采集页中的")
    .replace(/授权浏览器当前/g, "平台采集页当前")
    .replace(/请确认授权浏览器已登录/g, "请确认平台页面已登录")
    .replace(/授权浏览器/g, "平台授权页面")
    .replace(/本机浏览器/g, "平台授权页面")
    .replace(/手动 Cookie/g, "内部登录态")
    .replace(/Cookie 仅在本机/g, "登录态仅在本机")
    .replace(/Chrome\/Edge/g, "桌面客户端平台页面")
    .replace(/Chrome 窗口/g, "登录窗口");
}

function sanitizeLegacyAuthStatus(value) {
  if (value === "授权浏览器已启动" || value === "授权浏览器已打开") return "登录窗口已打开";
  return sanitizeLegacyAuthText(value);
}

function sanitizeLegacyAuthRecord(record, fields) {
  if (!record) return false;
  const before = JSON.stringify(record);
  for (const field of fields) {
    if (typeof record[field] === "string") record[field] = sanitizeLegacyAuthText(record[field]);
  }
  if (typeof record.status === "string") record.status = sanitizeLegacyAuthStatus(record.status);
  return JSON.stringify(record) !== before;
}

