  Array.from(document.querySelectorAll(editableSelector)).slice(-500).forEach((node) => addCandidate(node, "scan"));
  const best = candidates.sort((a, b) => b.score - a.score || b.rect.top - a.rect.top)[0];
  if (!reply) return { mounted: false, reason: "没有回复内容", url: location.href, candidates: candidates.slice(0, 4).map((item) => ({ score: item.score, text: item.text.slice(0, 50), source: item.source })) };
  if (!best?.node) return { mounted: false, reason: "抖音没有找到可写入的评论输入框", url: location.href, candidates: candidates.slice(0, 4).map((item) => ({ score: item.score, text: item.text.slice(0, 50), source: item.source })) };
