async function writeDb(db) {
  await fs.writeFile(dbPath, `${JSON.stringify(db, null, 2)}\n`, "utf8");
}

async function addLog(db, action, target, detail, actor = "运营员", tenantId = defaultTenantId) {
  const actorName = typeof actor === "object" && actor ? actor.name : actor;
  const resolvedTenantId = typeof actor === "object" && actor ? tenantIdForUser(actor) : tenantId;
  const tenant = (db.tenants || []).find((item) => item.id === resolvedTenantId);
  db.auditLogs.unshift({
    id: makeId("log"),
    tenantId: resolvedTenantId,
    tenantName: tenant?.name || defaultTenantName,
    actor: actorName,
    action,
    target,
    detail,
    createdAt: now()
  });
}

function parseCookies(req) {
  return Object.fromEntries(
    String(req.headers.cookie || "")
      .split(";")
      .map((part) => part.trim())
      .filter(Boolean)
      .map((part) => {
        const index = part.indexOf("=");
        return [part.slice(0, index), decodeURIComponent(part.slice(index + 1))];
      })
  );
}

function currentUser(req, db) {
  const session = currentSession(req, db);
  if (session) return db.users.find((user) => user.id === session.userId) || null;
  if (!loginRequired()) return defaultRuntimeUser(db);
  return null;
}

function currentSession(req, db) {
  const cookies = parseCookies(req);
  const authHeader = String(req.headers.authorization || "");
  const headerSession = String(req.headers["x-mvp-session"] || "").trim();
  const bearerSession = authHeader.startsWith("Bearer ") ? authHeader.slice(7).trim() : "";
  const sessionId = cookies.mvp_session || headerSession || bearerSession;
  return (db.sessions || []).find((item) => item.id === sessionId && new Date(item.expiresAt) > new Date()) || null;
}

function loginRequired() {
  return process.env.HKT_REQUIRE_LOGIN !== "0" && process.env.HKT_AUTO_LOGIN !== "1";
}

function defaultRuntimeUser(db) {
  return findLoginUser(db.users, "admin")
    || db.users.find((user) => user.id === "user_admin")
    || db.users[0]
    || { id: "user_admin", username: "admin", name: "管理员", role: "管理员", tenantId: defaultTenantId, tenantName: defaultTenantName, isPlatformAdmin: true };
}

async function loginSelectedUser(db, selected, res) {
  const session = {
    id: makeId("sess"),
    userId: selected.id,
    createdAt: now(),
    expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 8).toISOString()
  };
  db.sessions = db.sessions.filter((item) => item.userId !== selected.id);
  db.sessions.push(session);
  res.setHeader("Set-Cookie", `mvp_session=${encodeURIComponent(session.id)}; Path=/; HttpOnly; SameSite=Lax`);
  await addLog(db, "登录", "会话", `${selected.name} · ${selected.role}`, selected.name, tenantIdForUser(selected));
  return session;
}

function can(user, action) {
  if (isPlatformAdmin(user)) return true;
  const rules = {
    "export": ["管理员", "运营"],
    "backup": ["管理员"],
    "task:update": ["管理员", "运营"],
    "lead:update": ["管理员", "运营", "销售"],
    "target:update": ["管理员", "运营"],
    "discovery:update": ["管理员", "运营"],
    "account:update": ["管理员", "运营", "销售"],
    "phone:update": ["管理员", "运营"]
  };
  return (rules[action] || []).includes(user.role);
}

function sendJson(res, status, payload) {
  const body = JSON.stringify(payload);
  res.writeHead(status, {
    "Content-Type": "application/json; charset=utf-8",
    "Content-Length": Buffer.byteLength(body)
  });
  res.end(body);
}

function sendText(res, status, text, contentType = "text/plain; charset=utf-8") {
  res.writeHead(status, {
    "Content-Type": contentType,
    "Content-Length": Buffer.byteLength(text)
  });
  res.end(text);
}

async function readJsonFileSafe(filePath, fallback = {}) {
  try {
    return JSON.parse(await fs.readFile(filePath, "utf8"));
  } catch {
    return fallback;
  }
}

async function statFileSafe(filePath) {
  try {
    const stat = await fs.stat(filePath);
    return {
      exists: true,
      bytes: stat.size,
      updatedAt: stat.mtime.toISOString()
    };
  } catch {
    return { exists: false, bytes: 0, updatedAt: "" };
  }
}

async function tailTextFileSafe(filePath, maxLines = 40) {
  try {
    const text = await fs.readFile(filePath, "utf8");
    return text.split(/\r?\n/).filter(Boolean).slice(-maxLines);
  } catch {
    return [];
  }
}

async function sha256FileSafe(filePath) {
  try {
    const buffer = await fs.readFile(filePath);
    return crypto.createHash("sha256").update(buffer).digest("hex");
  } catch {
    return "";
  }
}

async function buildDiagnostics(db, user, license) {
  const packageJson = await readJsonFileSafe(packageJsonPath, {});
  const dbStat = await statFileSafe(dbPath);
  const licenseStat = await statFileSafe(licensePath);
  const aiSettingsStat = await statFileSafe(aiSettingsPath);
  const crashLogPath = path.join(path.dirname(dataDir), "logs", "crash.log");
  const crashLogStat = await statFileSafe(crashLogPath);
  const installerPath = path.join(root, "release", supportPackageName);
  const installerStat = await statFileSafe(installerPath);
  const installerSha256 = installerStat.exists ? await sha256FileSafe(installerPath) : "";
  const scopedDb = scopeDbForUser(db, user);
  return {
    generatedAt: now(),
    productName: packageJson.productName || "木桃工具包",
    version: packageJson.version || "0.1.0",
    licenseCenterMode,
    node: process.version,
    platform: `${process.platform} ${process.arch}`,
    cwd: root,
    dataDir,
    dbPath,
    licensePath,
    licenseServerConfigured: Boolean(licenseServerUrl),
    licenseServerHost: licenseServerHost(),
    crashLogPath,
    installer: {
      path: installerPath,
      name: supportPackageName,
      exists: installerStat.exists,
      bytes: installerStat.bytes,
      updatedAt: installerStat.updatedAt,
      sha256: installerSha256
    },
    files: {
      database: dbStat,
      license: licenseStat,
      aiSettings: aiSettingsStat,
      crashLog: crashLogStat
    },
    license: {
      status: license.status,
      active: license.active,
      customer: license.customer || "",
      plan: license.plan || "",
      expiresAt: license.expiresAt || "",
      daysLeft: license.daysLeft ?? ""
    },
    tenant: {
      id: tenantIdForUser(user),
      name: tenantNameForUser(user)
    },
    counts: {
      tasks: (scopedDb.collectionTasks || []).length,
      leads: (scopedDb.leads || []).length,
      candidates: (scopedDb.discoveryCandidates || []).length,
      replyAccounts: (scopedDb.replyAccounts || []).length,
      taskRuns: (scopedDb.taskRuns || []).length,
      auditLogs: (scopedDb.auditLogs || []).length
    },
    recentTaskRuns: (scopedDb.taskRuns || []).slice(0, 8).map((item) => ({
      createdAt: item.createdAt,
      taskName: item.taskName,
      status: item.status,
      checked: item.checked,
      matched: item.matched,
      detail: item.detail
    })),
    recentAuditLogs: (scopedDb.auditLogs || []).slice(0, 8).map((item) => ({
      createdAt: item.createdAt,
      actor: item.actor,
      action: item.action,
      target: item.target,
      detail: item.detail
    })),
    recentCrashLog: await tailTextFileSafe(crashLogPath, 30)
  };
}

async function readBody(req) {
  const chunks = [];
  for await (const chunk of req) chunks.push(chunk);
  if (!chunks.length) return {};
  const raw = Buffer.concat(chunks).toString("utf8");
  const contentType = String(req.headers["content-type"] || "");
  if (contentType.includes("application/x-www-form-urlencoded")) {
    const params = new URLSearchParams(raw);
    if (params.has("__json")) {
      try {
        return JSON.parse(params.get("__json") || "{}");
      } catch {
        return {};
      }
    }
    return Object.fromEntries(params.entries());
  }
  return JSON.parse(raw);
}

function normalizeList(value) {
  const normalizeItem = (item) => {
    const text = String(item || "").trim();
    if (text === "作品链接") return "作品URL";
    return text;
  };
  if (Array.isArray(value)) return value.map(normalizeItem).filter(Boolean);
  return String(value || "")
    .split(/[,\n，、]/)
    .map(normalizeItem)
    .filter(Boolean);
}

function normalizeTemplateList(value) {
  if (Array.isArray(value)) return value.map((item) => String(item || "").trim()).filter(Boolean);
  return String(value || "")
    .split(/\n+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeInteractionActions(value) {
  const allowed = ["点赞", "关注", "私信", "评论"];
  const aliases = {
    like: "点赞",
    follow: "关注",
    message: "私信",
    comment: "评论",
    "执行点赞": "点赞",
    "执行关注": "关注",
    "执行私信": "私信",
    "执行评论": "评论"
  };
  const items = normalizeList(value).map((item) => aliases[item] || item).filter((item) => allowed.includes(item));
  return uniqueList(items.length ? items : ["评论"]);
}

function normalizeOutreachMode(value) {
  const text = String(value || "").trim();
  if (["人工确认", "半自动确认", "官方号授权自动"].includes(text)) return text;
  if (text.includes("官方")) return "官方号授权自动";
  if (text.includes("半自动")) return "半自动确认";
  return "人工确认";
}

function accountHealthPercent(account) {
  const explicit = Number(account?.healthBasePercent || account?.healthPercent || 0);
  const baseline = explicit > 0 ? Math.max(1, Math.min(explicit, 100)) : 100;
  const replyLimit = normalizeReplyAccountLimit(account?.dailyReplyLimit, { bumpLegacy: true });
  const collectLimit = Math.max(1, Number(account?.dailyCollectLimit || 500));
  const touchLimit = normalizeReplyAccountLimit(account?.dailyTouchLimit || replyLimit, { bumpLegacy: true });
  const replyLoad = Number(account?.todayReplies || 0) / replyLimit;
  const collectLoad = Number(account?.todayCollections || 0) / collectLimit;
  const touchLoad = Number(account?.todayTouches || account?.todayReplies || 0) / touchLimit;
  const load = Math.max(replyLoad, collectLoad, touchLoad);
  const statusPenalty = account?.status === "启用" ? 0 : 25;
  const authPenalty = account?.credentialStatus && !String(account.credentialStatus).includes("未") ? 0 : 10;
  const cooldownPenalty = replyAccountCooldownActive(account) ? 45 : 0;
  return Math.max(0, Math.min(100, Math.round(baseline - load * 70 - statusPenalty - authPenalty - cooldownPenalty)));
}

function normalizeReplyAccountLimit(value, options = {}) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return maxReplyAccountLimit;
  if (options.bumpLegacy === true && numeric === legacyReplyAccountLimit) return maxReplyAccountLimit;
  return Math.max(1, Math.min(Math.round(numeric), maxReplyAccountLimit));
}

function parseBulkComments(value) {
  const extractUserId = (text) => {
    const match = String(text || "").match(/(?:抖音号|小红书号|用户ID|用户号|ID)\s*[:：]?\s*([A-Za-z0-9._-]{3,40})/i);
    return match ? match[1] : "";
  };
  const extractIpLocation = (text) => {
    const match = String(text || "").match(/(?:IP属地|属地|来自)[:：\s]*([\u4e00-\u9fa5A-Za-z0-9_-]{2,20})/);
    return match ? match[1] : "";
  };
  const cleanContent = (text) => String(text || "")
    .replace(/(?:抖音号|小红书号|用户ID|用户号|ID)\s*[:：]?\s*[A-Za-z0-9._-]{3,40}/gi, " ")
    .replace(/(?:^|\s)(?:IP属地|属地|来自)[:：\s]*[\u4e00-\u9fa5A-Za-z0-9_-]{2,20}(?=\s|$)/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  const isLikelyLocation = (text) => {
    const value = String(text || "").trim().replace(/^IP属地[:：\s]*/, "");
    if (!value || value.length > 20) return false;
    if (/[省市区县州盟]$/.test(value)) return true;
    return /^(北京|上海|天津|重庆|河北|山西|辽宁|吉林|黑龙江|江苏|浙江|安徽|福建|江西|山东|河南|湖北|湖南|广东|海南|四川|贵州|云南|陕西|甘肃|青海|台湾|内蒙古|广西|西藏|宁夏|新疆|香港|澳门|长春|成都|广州|深圳|杭州|南京|武汉|西安|郑州|长沙|沈阳|哈尔滨|济南|青岛|苏州|无锡|宁波|厦门|福州|昆明|贵阳|南宁|合肥|南昌|太原|石家庄|乌鲁木齐|兰州|银川|西宁|拉萨)$/.test(value);
  };
  return String(value || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line, index) => {
      const delimiter = ["\t", "|"].find((item) => line.includes(item));
      if (!delimiter) {
        const ipLocation = extractIpLocation(line);
        const inlineMatch = line.match(/^(.{1,40}?)(?:[（(]\s*(?:抖音号|小红书号|用户ID|用户号|ID)\s*[:：]?\s*([A-Za-z0-9._-]{3,40})\s*[）)])?\s*[:：]\s*(.+)$/);
        if (inlineMatch && !/^https?:\/\//i.test(inlineMatch[1])) {
          return {
            authorAlias: cleanContent(inlineMatch[1]).replace(/[（(]\s*$/, "").trim() || `批量评论${index + 1}`,
            sourceUserId: inlineMatch[2] || extractUserId(line),
            ipLocation,
            content: cleanContent(inlineMatch[3])
          };
        }
        return { authorAlias: `批量评论${index + 1}`, sourceUserId: extractUserId(line), ipLocation, content: cleanContent(line) };
      }
      const parts = line.split(delimiter).map((item) => item.trim());
      const [authorAlias, secondPart = "", thirdPart = "", ...restParts] = parts;
      const looksLikeUserId = (text) => /^[A-Za-z0-9._-]{3,40}$/.test(String(text || "")) && !isLikelyLocation(text);
      const hasUserIdAndLocation = parts.length >= 4 && looksLikeUserId(secondPart) && isLikelyLocation(thirdPart);
      const hasUserIdOnly = parts.length >= 3 && looksLikeUserId(secondPart) && !isLikelyLocation(secondPart);
      const hasLocationColumn = !hasUserIdAndLocation && parts.length >= 3 && isLikelyLocation(secondPart);
      const sourceUserId = hasUserIdAndLocation || hasUserIdOnly ? secondPart : extractUserId(line);
      const ipLocation = hasUserIdAndLocation
        ? thirdPart.replace(/^IP属地[:：\s]*/, "")
        : hasLocationColumn
          ? secondPart.replace(/^IP属地[:：\s]*/, "")
          : extractIpLocation(parts.slice(1).join(delimiter));
      const rawContent = hasUserIdAndLocation
        ? restParts.join(delimiter)
        : hasUserIdOnly
          ? [thirdPart, ...restParts].join(delimiter)
          : hasLocationColumn ? [thirdPart, ...restParts].join(delimiter) : parts.slice(1).join(delimiter);
      return {
        authorAlias: authorAlias.trim() || `批量评论${index + 1}`,
        sourceUserId,
        ipLocation,
        content: cleanContent(rawContent)
      };
    })
    .filter((item) => item.content);
}

function runAdbDevices() {
  return new Promise((resolve) => {
    const child = spawn("adb", ["devices"], { stdio: ["ignore", "pipe", "pipe"] });
    let stdout = "";
    let stderr = "";
    const timer = setTimeout(() => {
      child.kill("SIGTERM");
      resolve({ ok: false, devices: [], message: "手机连接检测超时，请确认已安装手机调试工具并允许数据线调试。" });
    }, 3500);
    child.stdout.on("data", (chunk) => {
      stdout += chunk.toString("utf8");
    });
    child.stderr.on("data", (chunk) => {
      stderr += chunk.toString("utf8");
    });
    child.on("error", () => {
      clearTimeout(timer);
      resolve({ ok: false, devices: [], message: "未检测到手机调试工具，请先安装 Android 调试工具。" });
    });
    child.on("close", (code) => {
      clearTimeout(timer);
      if (code !== 0) {
        resolve({ ok: false, devices: [], message: stderr.trim() || "手机连接检测失败，请检查手机连接。" });
        return;
      }
      const devices = stdout
        .split(/\r?\n/)
        .map((line) => line.trim())
        .filter((line) => line && !line.startsWith("List of devices"))
        .map((line) => {
          const [serial, state] = line.split(/\s+/);
          return { serial, state };
        });
      resolve({
        ok: devices.some((item) => item.state === "device"),
        devices,
        message: devices.length ? `检测到 ${devices.length} 台设备。` : "未检测到手机，请连接数据线并开启调试授权。"
      });
    });
  });
}

function parseOfficialLeadRows(value) {
  return String(value || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .filter((line, index) => !(index === 0 && /姓名|客户|手机|电话|微信|留言/.test(line)))
    .map((line) => {
      const delimiter = ["\t", "|", ","].find((item) => line.includes(item));
      const parts = delimiter ? line.split(delimiter).map((item) => item.trim()) : [line];
      return {
        customerName: parts[0] || "留资客户",
        phone: parts[1] || "",
        wechat: parts[2] || "",
        content: parts.slice(3).join(" ").trim() || parts[0] || ""
      };
    })
    .filter((row) => row.customerName || row.phone || row.wechat || row.content);
}

function buildMetrics(db) {
  const activeTasks = db.tasks.filter((task) => task.status !== "已暂停").length;
  const openLeads = db.leads.filter((lead) => !["已完成", "已转化", "已屏蔽"].includes(lead.status)).length;
  const completedLeads = db.leads.filter((lead) => ["已完成", "已转化"].includes(lead.status)).length;
  const convertedLeads = db.leads.filter((lead) => lead.status === "已转化").length;
  const workableLeads = db.leads.filter((lead) => lead.status !== "已屏蔽").length;
  const privateDomainLeads = db.leads.filter((lead) => lead.status === "已转化" && lead.conversionDestination === "私域").length;
  const ownedCustomerLeads = db.leads.filter((lead) => lead.status === "已转化" && lead.conversionDestination === "自有客户池").length;
  const conversionRate = workableLeads ? Math.round((convertedLeads / workableLeads) * 100) : 0;
  const safetyFlags = db.tasks.filter((task) => task.status === "合规评估").length;
  const trackedTargets = (db.trackedTargets || []).length;
  const contactableLeads = db.leads.filter((lead) => lead.contactPolicy === "可外联").length;
  const candidates = (db.discoveryCandidates || []).filter((item) => item.status === "待确认").length;
  const approvedRequirements = (db.toolRequirements || []).filter((item) => item.decision === "吸收").length;
  const collectionTasks = (db.collectionTasks || []).length;
  const accountMonitors = (db.accountMonitors || []).length;
  const replyAccounts = (db.replyAccounts || []).length;
  const activeReplyAccounts = (db.replyAccounts || []).filter((item) => item.status === "启用").length;
  const phoneDevices = (db.phoneDevices || []).length;
  const phoneCollectionTasks = (db.phoneCollectionTasks || []).length;
  const activePhoneCollectionTasks = (db.phoneCollectionTasks || []).filter((item) => !["已完成", "已暂停"].includes(item.status)).length;
  const officialLeadConfigs = (db.officialLeadConfigs || []).length;
  const officialLeads = db.leads.filter(isOfficialLeadRecord);
  const openOfficialLeads = officialLeads.filter((lead) => !["已完成", "已转化", "已屏蔽"].includes(lead.status)).length;
  const convertedOfficialLeads = officialLeads.filter((lead) => lead.status === "已转化").length;
  return {
    activeTasks,
    openLeads,
    completedLeads,
    convertedLeads,
    privateDomainLeads,
    ownedCustomerLeads,
    conversionRate,
    safetyFlags,
    trackedTargets,
    contactableLeads,
    candidates,
    approvedRequirements,
    collectionTasks,
    accountMonitors,
    replyAccounts,
    activeReplyAccounts,
    phoneDevices,
    phoneCollectionTasks,
    activePhoneCollectionTasks,
    officialLeadConfigs,
    officialLeads: officialLeads.length,
    openOfficialLeads,
    convertedOfficialLeads,
    progress: 52
  };
}

function ensureReplyAccountUsage(account) {
  if (!account.usageDate || account.usageDate !== usageDateKey()) {
    account.usageDate = usageDateKey();
    account.todayReplies = 0;
    account.todayCollections = 0;
    account.todayTouches = 0;
  }
  const cooldownTime = Date.parse(account.cooldownUntil || "");
  if (account.cooldownUntil && (!Number.isFinite(cooldownTime) || cooldownTime <= Date.now())) {
    account.lastCooldownUntil = account.cooldownUntil;
    delete account.cooldownUntil;
    delete account.cooldownReason;
  }
  if (!Array.isArray(account.auditTrail)) account.auditTrail = [];
  if (account.todayReplies === undefined) account.todayReplies = 0;
  if (account.todayCollections === undefined) account.todayCollections = 0;
  if (account.todayTouches === undefined) account.todayTouches = Number(account.todayReplies || 0);
  account.dailyReplyLimit = normalizeReplyAccountLimit(account.dailyReplyLimit, { bumpLegacy: true });
  if (!account.dailyCollectLimit) account.dailyCollectLimit = 80;
  account.dailyTouchLimit = normalizeReplyAccountLimit(account.dailyTouchLimit || account.dailyReplyLimit, { bumpLegacy: true });
  return account;
}

function replyAccountCooldownActive(account) {
  const timestamp = Date.parse(account?.cooldownUntil || "");
  return Number.isFinite(timestamp) && timestamp > Date.now();
}

function cooldownReplyAccount(account, reason, options = {}) {
  if (!account) return platformRateLimitReason(reason) || String(reason || "平台提示回复过于频繁，已暂停自动回复并冷却账号。");
  ensureReplyAccountUsage(account);
  const minutes = Math.max(5, Math.min(Number(options.minutes || defaultPlatformRateLimitCooldownMinutes), 180));
  const cooldownUntil = new Date(Date.now() + minutes * 60 * 1000).toISOString();
  const detail = platformRateLimitReason(reason) || String(reason || "平台提示回复过于频繁，已暂停自动回复并冷却账号。");
  account.cooldownUntil = cooldownUntil;
  account.cooldownReason = detail;
  account.lastPlatformWarningAt = now();
  account.updatedAt = now();
  account.auditTrail = Array.isArray(account.auditTrail) ? account.auditTrail : [];
  account.auditTrail.unshift({
    id: makeId("acctlog"),
    actor: options.actor || "系统",
    action: "账号冷却",
    detail: `${detail} 冷却至 ${cooldownUntil}`,
    createdAt: now()
  });
  account.auditTrail = account.auditTrail.slice(0, 20);
  account.healthPercent = accountHealthPercent(account);
  return `${detail}账号已冷却 ${minutes} 分钟，冷却至 ${cooldownUntil}。`;
}

function replyAccountHasUsableAuth(account) {
  const credential = String(account?.credentialStatus || "");
  const browserStatus = String(account?.browserAuthStatus || "");
  const session = account?.id ? browserAuthSessions.get(account.id) : null;
  const windowReady = isAuthSessionAlive(session) && /登录窗口已打开|采集窗口已打开|真实浏览器已打开|平台页面已打开|账号已授权|页面检测通过/.test(browserStatus);
  return credential === "账号已授权"
    || credential === "窗口授权可用"
    || credential === "本地格式通过"
    || (credential === "已保存待校验" && Boolean(account?.cookieCipher))
    || (Boolean(account?.partitionAuthSavedAt) && !/未绑定|读取失败|检测失败|页面未登录/.test(credential))
    || (Boolean(account?.cookieCipher) && !/未绑定|读取失败|检测失败|页面未登录/.test(credential))
    || /账号已授权|页面检测通过|本地格式通过/.test(browserStatus)
    || windowReady;
}

function replyAccountCanExecute(account) {
  ensureReplyAccountUsage(account);
  return account.status === "启用"
    && replyAccountHasUsableAuth(account)
    && !replyAccountCooldownActive(account)
    && Number(account.todayReplies || 0) < normalizeReplyAccountLimit(account.dailyReplyLimit)
    && Number(account.todayTouches || 0) < normalizeReplyAccountLimit(account.dailyTouchLimit || account.dailyReplyLimit);
}

function replyAccountCanLaunchExecution(account) {
  ensureReplyAccountUsage(account);
  return account.status === "启用"
    && !replyAccountCooldownActive(account)
    && Number(account.todayReplies || 0) < normalizeReplyAccountLimit(account.dailyReplyLimit)
    && Number(account.todayTouches || 0) < normalizeReplyAccountLimit(account.dailyTouchLimit || account.dailyReplyLimit);
}

function replyAccountCanExecuteOrLaunch(account) {
  return replyAccountCanExecute(account) || replyAccountCanLaunchExecution(account);
}

function activateAuthorizedReplyAccount(account, actor = "系统", reason = "授权账号进入执行队列") {
  if (!account || account.status === "启用" || !replyAccountHasUsableAuth(account)) return false;
  account.status = "启用";
  account.updatedAt = now();
  account.auditTrail = Array.isArray(account.auditTrail) ? account.auditTrail : [];
  account.auditTrail.unshift({
    id: makeId("acctlog"),
    actor,
    action: "自动启用账号",
    detail: reason,
    createdAt: now()
  });
  account.auditTrail = account.auditTrail.slice(0, 20);
  return true;
}

function activateAuthorizedReplyAccountsForPlatform(db, user, tenantId, platform, reason = "同平台授权账号进入执行队列") {
  let changed = 0;
  for (const account of db.replyAccounts || []) {
    if (!canAccessRecord(user, account) || recordTenantId(account) !== tenantId) continue;
    if (platformAuthConfig(account.platform).key !== platformAuthConfig(platform || "").key) continue;
    if (activateAuthorizedReplyAccount(account, user.name || "系统", reason)) changed += 1;
  }
  return changed;
}

function replyAccountExecutionBlockReason(account) {
  ensureReplyAccountUsage(account);
  if (account.status !== "启用") return "回复账号未启用";
  if (!replyAccountHasUsableAuth(account)) return "回复账号未完成授权";
  if (replyAccountCooldownActive(account)) return `回复账号冷却中，冷却至 ${account.cooldownUntil}：${account.cooldownReason || "平台提示回复频率过高"}`;
  if (Number(account.todayReplies || 0) >= normalizeReplyAccountLimit(account.dailyReplyLimit)) return "该账号今日回复配额已用完";
  if (Number(account.todayTouches || 0) >= normalizeReplyAccountLimit(account.dailyTouchLimit || account.dailyReplyLimit)) return "该账号今日触达配额已用完";
  return "";
}

function nextAvailableReplyAccount(db, user, lead, currentAccount = null) {
  const tenantId = recordTenantId(lead);
  const platformKey = platformAuthConfig(lead?.platform || currentAccount?.platform || "").key;
  return (db.replyAccounts || [])
    .filter((account) => account.id !== currentAccount?.id)
    .filter((account) => canAccessRecord(user, account) && recordTenantId(account) === tenantId)
    .filter((account) => platformAuthConfig(account.platform).key === platformKey)
    .sort((left, right) => Number(left.todayTouches || 0) - Number(right.todayTouches || 0))
    .find((account) => replyAccountCanExecuteOrLaunch(account)) || null;
}

function firstExecutableReplyAccountForPlatform(db, user, tenantId, platform, excludeId = "") {
  const platformKey = platformAuthConfig(platform || "").key;
  return (db.replyAccounts || [])
    .filter((account) => account.id !== excludeId)
    .filter((account) => canAccessRecord(user, account) && recordTenantId(account) === tenantId)
    .filter((account) => platformAuthConfig(account.platform).key === platformKey)
    .sort((left, right) => Number(left.todayTouches || 0) - Number(right.todayTouches || 0))
    .find((account) => replyAccountCanExecute(account))
    || (db.replyAccounts || [])
      .filter((account) => account.id !== excludeId)
      .filter((account) => canAccessRecord(user, account) && recordTenantId(account) === tenantId)
      .filter((account) => platformAuthConfig(account.platform).key === platformKey)
      .sort((left, right) => Number(left.todayTouches || 0) - Number(right.todayTouches || 0))
      .find((account) => replyAccountCanLaunchExecution(account))
    || null;
}

function executableReplyAccountsForPlatform(db, user, tenantId, platform, preferredAccount = null) {
  const platformKey = platformAuthConfig(platform || preferredAccount?.platform || "").key;
  const accounts = (db.replyAccounts || [])
    .filter((account) => canAccessRecord(user, account) && recordTenantId(account) === tenantId)
    .filter((account) => platformAuthConfig(account.platform).key === platformKey)
    .filter((account) => replyAccountCanExecuteOrLaunch(account))
    .sort((left, right) => Number(left.todayTouches || 0) - Number(right.todayTouches || 0));
  const rotation = [];
  const seen = new Set();
  const add = (account) => {
    if (!account?.id || seen.has(account.id)) return;
    if (!samePlatformName(account.platform, platform) || recordTenantId(account) !== tenantId || !replyAccountCanExecuteOrLaunch(account)) return;
    ensureReplyAccountUsage(account);
    seen.add(account.id);
    rotation.push(account);
  };
  add(preferredAccount);
  accounts.forEach(add);
  return rotation;
}

function nextReplyRotationIndex(rotationAccounts, currentIndex) {
  for (let offset = 1; offset <= rotationAccounts.length; offset += 1) {
    const nextIndex = (currentIndex + offset) % rotationAccounts.length;
    if (replyAccountCanExecuteOrLaunch(rotationAccounts[nextIndex])) return nextIndex;
  }
  return -1;
}

function samePlatformName(left, right) {
  return platformAuthConfig(left || "").key === platformAuthConfig(right || "").key;
}

function uniqueList(values) {
  return Array.from(new Set(values.map((item) => String(item || "").trim()).filter(Boolean)));
}

function platformAliases(value) {
  const text = String(value || "").trim();
  if (["抖音企业号", "抖音作品/评论", "抖音"].includes(text)) return ["抖音企业号", "抖音作品/评论", "抖音"];
  return [text];
}

function buildSearchUrl(platform, keyword) {
  const q = encodeURIComponent(keyword);
  if (platform === "小红书笔记/评论") return `https://www.xiaohongshu.com/search_result?keyword=${q}`;
  if (platform === "快手") return `https://www.kuaishou.com/search/video?searchKey=${q}`;
  return `https://www.douyin.com/search/${q}`;
}

function industryKeywords(industry, region = "", targetTerms = []) {
  const base = normalizeList(industry).length ? normalizeList(industry) : [String(industry || "").trim()].filter(Boolean);
  const regions = normalizeList(region);
  const seeds = base.length ? base : ["本地生活"];
  const terms = normalizeList(targetTerms);
  return uniqueList([
    ...seeds,
    ...terms,
    ...seeds.flatMap((item) => terms.map((term) => `${item}${term}`)),
    ...seeds.map((item) => `${item}多少钱`),
    ...seeds.map((item) => `${item}地址`),
    ...seeds.map((item) => `${item}团购`),
    ...seeds.map((item) => `${item}推荐`),
    ...seeds.map((item) => `${item}好看`),
    ...regions.flatMap((item) => [`${item}${seeds[0]}`, `${item}${seeds[0]}团购`, `${item}${seeds[0]}探店`])
  ]).slice(0, 12);
}

function buildIndustryDiscovery(body) {
  const industry = String(body.industry || "本地生活").trim();
  const region = String(body.region || "").trim();
  const regions = normalizeList(region);
  const platforms = normalizeList(body.platforms || "小红书笔记/评论,抖音作品/评论").filter((item) => ["小红书笔记/评论", "抖音作品/评论", "抖音企业号", "快手"].includes(item));
  const heatMetric = String(body.heatMetric || "评论量").trim();
  const heatWindow = String(body.heatWindow || "近7天").trim();
  const heatTerms = normalizeList(body.triggers || "热门,爆款,探店,测评,团购,评论多,播放高,转发多");
  const keywords = industryKeywords(industry, region, heatTerms).map((keyword) => `${keyword} ${heatMetric} ${heatWindow}`);
  const searchLinks = platforms.flatMap((platform) => keywords.slice(0, 6).map((keyword) => ({
    platform,
    keyword,
    url: buildSearchUrl(platform, keyword)
  })));
  const targetRegions = regions.length ? regions : [region];
  const suggestedTargets = platforms.flatMap((platform) => targetRegions.flatMap((item) => [
    {
      platform,
      type: "作品URL",
      name: `${item || "全国"}${industry}${heatWindow}热视频池`,
      region: item,
      url: buildSearchUrl(platform, `${item}${industry} ${heatMetric} ${heatWindow}`),
      reason: `优先找${heatWindow}${heatMetric}较高的视频，再进入作品链接采集评论。`
    },
    {
      platform,
      type: "达人账号",
      name: `${item || "全国"}${industry}热作者池`,
      region: item,
      url: buildSearchUrl(platform, `${item}${industry} 热门作者 ${heatWindow}`),
      reason: "优先观察近期连续产出热视频的作者账号。"
    }
  ]));
  return { industry, region, platforms, keywords, heatMetric, heatWindow, searchLinks, suggestedTargets };
}

function collectionTaskRule(task) {
  const platforms = normalizeList(task.platform || "抖音作品/评论");
  return {
    id: `collect_rule_${task.id}`,
    tenantId: recordTenantId(task),
    tenantName: task.tenantName || defaultTenantName,
    name: `${task.title || task.mode || "采集任务"}意向识别`,
    targetTypes: ["店铺账号", "达人账号", "博主账号", "作品URL", "直播间", "自有粉丝", "互动用户", "官方留资", "观察对象"],
    platforms: platforms.length ? platforms : ["抖音作品/评论"],
    regions: normalizeList(task.region || ""),
    triggers: task.triggers || [],
    blocks: task.blocks || [],
    minScore: 70,
    minContentLength: Number(task.minContentLength || 0),
    contactPolicy: "需人工确认",
    status: "启用"
  };
}

function sampleMatchesCollectionTask(task, sample, target = null) {
  if (task.targetId && sample.targetId !== task.targetId) return false;
  if (!matchesAny([sample.platform || target?.platform], normalizeList(task.platform || ""))) return false;
  if (!matchesAny([sample.region || target?.region], normalizeList(task.region || ""))) return false;
  if (Number(task.minContentLength || 0) > 0 && contentLength(sample.content) < Number(task.minContentLength || 0)) return false;
  const { blocked } = findSignals({ blocks: task.blocks || [], triggers: [] }, `${sample.authorAlias || ""} ${sample.content || ""}`);
  return !blocked;
}

function collectionTaskSamples(db, task) {
  const tenantId = recordTenantId(task);
  const targetMap = new Map((db.trackedTargets || []).filter((target) => recordTenantId(target) === tenantId).map((target) => [target.id, target]));
  return (db.sourceSamples || [])
    .filter((sample) => recordTenantId(sample) === tenantId)
    .filter((sample) => sampleMatchesCollectionTask(task, sample, targetMap.get(sample.targetId)))
    .slice(0, collectionTaskMatchLimit(task));
}

function sampleMatchesKeywordIngest(task, sample) {
  const triggers = normalizeList(task.triggers || []);
  if (!triggers.length) return false;
  const text = `${sample.authorAlias || ""} ${sample.content || ""} ${sample.region || ""}`;
  const { blocked, signals } = findSignals({ blocks: task.blocks || [], triggers }, text);
  return !blocked && signals.length > 0;
}

function leadIngestSamplesForTask(task, samples) {
  const ingestMode = normalizeLeadIngestMode(task.leadIngestMode);
  if (ingestMode !== "关键字采集" && ingestMode !== "边采集边回复") return samples || [];
  return (samples || []).filter((sample) => sampleMatchesKeywordIngest(task, sample));
}

async function runCollectionTask(db, task, user, aiSettings) {
  const startedAt = now();
  task.runStatus = "运行中";
  task.status = "运行中";
  task.failureReason = "";
  task.updatedAt = startedAt;
  task.runLogs = Array.isArray(task.runLogs) ? task.runLogs : [];

  const autoCollect = await autoCollectVisibleCommentsForTask(db, task, user);
  const samples = collectionTaskSamples(db, task);
  const rule = collectionTaskRule(task);
  const candidates = await runDiscoveryRule(db, rule, aiSettings, {
    sampleIds: new Set(samples.map((sample) => sample.id)),
    skipTargetFallback: true
  });
  const leadSamples = leadIngestSamplesForTask(task, samples);
  const leadAssets = materializeSampleLeads(db, leadSamples, user);
  const totalMatched = (db.discoveryCandidates || []).filter((candidate) => recordTenantId(candidate) === recordTenantId(task) && candidate.ruleId === rule.id).length;
  task.collected = samples.length;
  task.ingested = leadSamples.length;
  task.matched = totalMatched;
  task.lastRunAt = now();
  task.autoCollectStatus = autoCollect.attempted
    ? autoCollect.imported > 0 ? "已自动采集" : autoCollect.checked > 0 ? "无新增评论" : "需检查采集页"
    : "未触发";
  task.autoCollected = Number(task.autoCollected || 0) + Number(autoCollect.imported || 0);
  task.autoCollectMessage = autoCollect.message || "";
  task.lastAutoCollectAt = autoCollect.attempted ? now() : task.lastAutoCollectAt || "";
  const emptyRunStatus = autoCollect.reason === "no_account"
    ? "等待账号授权"
    : autoCollect.reason === "collector_unreachable"
      ? "采集页未连接"
      : autoCollect.reason === "needs_work_url"
        ? "需选择作品"
        : autoCollect.reason === "no_visible_comments"
          ? "未识别到评论"
          : autoCollect.attempted ? "采集未完成" : "等待评论池";
  task.runStatus = samples.length ? "已完成" : emptyRunStatus;
  task.status = task.runStatus;
  task.failureReason = samples.length ? "" : autoCollect.message || "暂无符合条件的评论来源，请先从批量导入或可见采集入口进入评论池。";
  const autoDetail = autoCollect.message ? `${autoCollect.message} ` : "";
  const scopeDetail = normalizeCollectMode(task.collectMode) === "全量采集"
    ? "全量范围：当前作品页可见评论最多 500 条，评论池识别最多 500 条。"
    : "";
  const ingestMode = normalizeLeadIngestMode(task.leadIngestMode);
  const keywordNote = (task.triggers || []).length ? `，关键词：${(task.triggers || []).slice(0, 6).join("、")}` : "，未设置关键词";
  const ingestDetail = ingestMode === "边采集边回复"
    ? `边采集边回复 ${leadSamples.length}/${samples.length} 条${keywordNote}，命中后进入精准回复队列。`
    : ingestMode === "关键字采集"
      ? `关键字采集入池 ${leadSamples.length}/${samples.length} 条${keywordNote}。`
      : `全量采集入池 ${leadSamples.length} 条。`;
  const detail = samples.length
    ? `${autoDetail}${scopeDetail}评论池检查 ${samples.length} 条，${ingestDetail}沉淀线索新增 ${leadAssets.created} 条、合并 ${leadAssets.merged} 条；本次筛出意向候选 ${candidates.length} 条，累计候选 ${totalMatched} 条。未进入线索池的评论仍保留在评论池备查。`
    : task.failureReason;
  const run = {
    id: makeId("run"),
    tenantId: recordTenantId(task),
    tenantName: task.tenantName || defaultTenantName,
    taskId: task.id,
    taskName: `${task.platform} · ${task.mode}`,
    status: task.runStatus,
    checked: samples.length,
    matched: candidates.length,
    detail,
    createdAt: now()
  };
  task.runLogs.unshift(run);
  task.runLogs = task.runLogs.slice(0, 10);
  db.taskRuns.unshift(run);
  await addLog(db, "运行采集任务", task.title, detail, user.name, recordTenantId(task));
  return { task, generated: candidates.length, checked: samples.length, totalMatched, autoCollect };
}

async function runAccountMonitorCheck(db, monitor, user, aiSettings, options = {}) {
  const checkedAt = now();
  monitor.lastCheckedAt = checkedAt;
  monitor.updatedAt = checkedAt;
  monitor.nextAutoCheckAt = monitor.autoCheckEnabled ? nextMonitorCheckAt(monitor, new Date(checkedAt)) : "";
  const task = ensureMonitorCollectionTask(db, monitor, user);
  const isWork = isLikelyWorkUrl(task.url);
  const canRun = isWork && monitorCanRunAutoCollect(monitor);
  let status = options.scheduled ? "自动巡检已触发" : "已检查";
  let checked = 0;
  let matched = 0;
  let detail = "";

  if (canRun) {
    ensureCollectionTaskTarget(db, task, user);
    const result = await runCollectionTask(db, task, user, aiSettings);
    const imported = Number(result.autoCollect?.imported || 0);
    checked = Number(result.checked || 0);
    matched = Number(result.generated || 0);
    monitor.status = result.task.runStatus === "已完成" ? "已自动采集" : result.task.runStatus;
    monitor.newComments = imported;
    monitor.newCandidates = matched;
    monitor.autoCollectImported = Number(monitor.autoCollectImported || 0) + imported;
    monitor.autoCollectMatched = Number(monitor.autoCollectMatched || 0) + matched;
    monitor.lastAutoCollectAt = now();
    monitor.lastAutoCollectTaskId = task.id;
    monitor.lastAutoCollectMessage = result.autoCollect?.message || result.task.failureReason || "";
    status = monitor.status;
    detail = `${monitor.automationLevel || "授权窗口半自动"} · 已关联任务 ${task.title}；${monitor.lastAutoCollectMessage || `检查 ${checked} 条评论，新增候选 ${matched} 条。`}`;
  } else if (isWork) {
    monitor.status = "待授权采集";
    monitor.newComments = 0;
    monitor.newCandidates = 0;
    monitor.lastAutoCollectTaskId = task.id;
    monitor.lastAutoCollectMessage = "已生成作品采集任务。当前自动化层级是自动记录巡检，请切换为授权窗口半自动或官方号授权自动后到点运行。";
    task.status = task.status === "需选择作品" ? "待采集" : task.status;
    task.runStatus = task.runStatus === "需选择作品" ? "待采集" : task.runStatus;
    status = monitor.status;
    detail = `${monitor.automationLevel || "自动记录巡检"} · 已生成关联采集任务 ${task.title}，等待授权采集或人工运行。`;
  } else {
    monitor.status = "待选择作品";
    monitor.newComments = 0;
    monitor.newCandidates = 0;
    monitor.lastAutoCollectTaskId = task.id;
    monitor.lastAutoCollectMessage = "当前是账号主页、搜索入口或空链接。先打开最新作品，把具体作品链接填入监控或作品任务后，才能自动读取评论。";
    task.status = "需选择作品";
    task.runStatus = "需选择作品";
    task.failureReason = monitor.lastAutoCollectMessage;
    status = monitor.status;
    detail = `${monitor.automationLevel || "自动记录巡检"} · 监控最新 ${monitor.monitorDepth || 10} 个作品，重点看 ${monitor.activeWithinMinutes || 1} 分钟内新评；当前入口还不是具体作品链接，已生成待选择作品任务。`;
  }

  db.taskRuns.unshift({
    id: makeId("run"),
    tenantId: recordTenantId(monitor),
    tenantName: monitor.tenantName || tenantNameForUser(user),
    taskId: monitor.id,
    taskName: `${monitor.platform} · ${monitor.accountName}`,
    status,
    checked,
    matched,
    detail,
    createdAt: now()
  });
  await addLog(db, options.scheduled ? "自动账号巡检" : "检查账号监控", monitor.accountName, detail, user, recordTenantId(monitor));
  return { monitor, task, checked, matched, detail, status };
}

async function buildSnackJilinDemo(db, user, aiSettings) {
  const tenantId = tenantIdForUser(user);
  const tenantName = tenantNameForUser(user);
  const tenantSuffix = tenantId === defaultTenantId ? "" : `_${shortHash(tenantId).slice(0, 8)}`;
  const targetId = `target_demo_jilin_snack${tenantSuffix}`;
  if (!(db.trackedTargets || []).some((target) => target.id === targetId && recordTenantId(target) === tenantId)) {
    db.trackedTargets.unshift({
      id: targetId,
      tenantId,
      tenantName,
      type: "作品URL",
      name: "吉林零食团购演示作品",
      platform: "抖音作品/评论",
      url: "demo://snack-jilin",
      region: "吉林",
      status: "观察中",
      contactPolicy: "需人工确认",
      note: "客户演示模式：公开评论/授权导入样本，不自动触达。",
      createdAt: now(),
      updatedAt: now()
    });
  }

  const taskId = `collect_demo_jilin_snack${tenantSuffix}`;
  let task = (db.collectionTasks || []).find((item) => item.id === taskId && recordTenantId(item) === tenantId);
  if (!task) {
    task = {
      id: taskId,
      tenantId,
      tenantName,
      mode: "客户演示",
      platform: "抖音作品/评论",
      title: "零食 + 吉林演示任务",
      url: "demo://snack-jilin",
      industry: "零食",
      region: "吉林,长春",
      triggers: ["多少钱", "地址", "配送", "团购", "批发", "采购", "一箱"],
      blocks: ["互粉", "广告", "抽奖"],
      minContentLength: 8,
      limit: 1000,
      status: "待采集",
      runStatus: "待采集",
      collected: 0,
      matched: 0,
      failureReason: "",
      runLogs: [],
      targetId,
      note: "一键演示评论池、任务运行、候选线索和去重合并。",
      createdAt: now(),
      updatedAt: now()
    };
    db.collectionTasks.unshift(task);
  }

  const demoSamples = [
    ["sample_demo_jilin_001", "吉林用户A", "吉林市能配送吗，团购多少钱，想给公司采购零食"],
    ["sample_demo_jilin_002", "吉林用户B", "这个零食好吃吗，多少钱一箱，可以配送吉林吗"],
    ["sample_demo_jilin_003", "长春采购C", "长春办公室下午茶想长期订，批发价怎么走"],
    ["sample_demo_jilin_004", "吉林用户D", "店铺地址在哪，周末可以到店买吗"],
    ["sample_demo_jilin_005", "无关用户E", "互粉一下，广告合作看主页"],
    ["sample_demo_jilin_006", "普通用户F", "看起来不错，下次试试"],
    ["sample_demo_jilin_007", "吉林用户A", "吉林市能配送吗，团购多少钱，想给公司采购零食"],
    ["sample_demo_jilin_008", "延边用户G", "延边能发货吗，整箱拿有没有优惠"]
  ];
  let imported = 0;
  const existingIds = new Set((db.sourceSamples || []).map((sample) => sample.id));
  const existingContent = new Set((db.sourceSamples || []).filter((sample) => recordTenantId(sample) === tenantId).map((sample) => `${sample.targetId}:${sample.authorAlias}:${sample.content}`));
  for (const [rawId, authorAlias, content] of demoSamples) {
    const id = `${rawId}${tenantSuffix}`;
    const contentKey = `${targetId}:${authorAlias}:${content}`;
    if (existingIds.has(id) || existingContent.has(contentKey)) continue;
    db.sourceSamples.unshift({
      id,
      tenantId,
      tenantName,
      targetId,
      targetName: "吉林零食团购演示作品",
      platform: "抖音作品/评论",
      sourceType: "演示评论",
      authorAlias,
      region: authorAlias.includes("长春") ? "长春" : "吉林",
      content,
      assetType: "互动用户",
      contactPolicy: "需人工确认",
      status: "待识别",
      createdAt: now()
    });
    imported += 1;
  }

  const run = await runCollectionTask(db, task, user, aiSettings);
  await addLog(db, "生成演示数据", "零食 + 吉林", `导入 ${imported} 条演示评论，新增候选 ${run.generated} 条`, user.name, tenantId);
  return {
    imported,
    checked: run.checked,
    generated: run.generated,
    totalMatched: run.totalMatched,
    taskId,
    targetId,
    report: `零食 + 吉林演示：评论池 ${run.checked} 条，本次新增候选 ${run.generated} 条，累计候选 ${run.totalMatched} 条。`
  };
}

function matchesAny(values, allowed) {
  if (!allowed || allowed.length === 0 || allowed.includes("全部")) return true;
  const allowedAliases = new Set(allowed.flatMap(platformAliases));
  return values
    .flatMap((value) => normalizeList(value))
    .some((value) => platformAliases(value).some((alias) => allowedAliases.has(alias)));
}

function findSignals(rule, text) {
  const normalized = String(text || "");
  const blocks = rule.blocks || [];
  if (blocks.some((block) => block && normalized.includes(block))) return { blocked: true, signals: [] };
  const signals = [];
  for (const trigger of rule.triggers || []) {
    if (trigger && normalized.includes(trigger)) signals.push(trigger);
  }
  return { blocked: false, signals };
}

function contentLength(value) {
  return Array.from(String(value || "").replace(/\s+/g, "")).length;
}

function compactFingerprint(value) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/[，。！？、,.!?;；:："“”"'‘’`~（）()【】\[\]{}<>《》]/g, "")
    .slice(0, 180);
}

function commentPersonKey(item) {
  return normalizeLeadContact(item?.sourceUserId)
    || normalizeLeadContact(item?.sourceUserProfileUrl)
    || normalizeLeadContact(item?.authorProfileUrl)
    || normalizeLeadContact(item?.sourceAuthorAlias || item?.authorAlias || item?.author)
    || "unknown";
}

function stableCommentPersonKey(item) {
  return normalizeLeadContact(item?.sourceUserId)
    || normalizeLeadContact(item?.sourceUserProfileUrl)
    || normalizeLeadContact(item?.authorProfileUrl)
    || "";
}

function commentContentKey(item) {
  const raw = String(item?.sourceComment || item?.content || item?.rawContent || "").trim();
  return compactFingerprint(raw) || shortHash(raw);
}

function commentDedupeKey(item) {
  return [
    item?.platform || "",
    commentPersonKey(item),
    commentContentKey(item)
  ].join("|");
}

function replyCommentSourceTargetKey(item) {
  const raw = String(item?.sourceTargetUrl || item?.sourceUrl || item?.pageUrl || item?.url || item?.workUrl || "").trim();
  if (!raw) return "unknown-work";
  const canonical = replyWorkIdentityUrl(raw, item?.platform || "") || canonicalWorkUrlFromUrl(raw, item?.platform || "") || firstUrlFromText(raw) || raw;
  return shortHash(canonical);
}

function retryLeadTaskKey(lead) {
  const raw = String(lead?.sourceTargetUrl || lead?.sourceUrl || lead?.pageUrl || lead?.url || "").trim();
  const platform = platformFromUrl(raw, lead?.platform || "抖音作品/评论");
  const canonical = canonicalWorkUrlFromUrl(raw, platform) || firstUrlFromText(raw) || raw || String(lead?.sourceTargetName || lead?.sourceName || "").trim();
  return `${platformAuthConfig(platform).key}::${canonical || "unknown-work"}`;
}

function replyCommentExecutionKey(item) {
  const rawComment = String(item?.sourceComment || item?.content || item?.rawContent || item?.commentText || "").trim();
  if (!rawComment) return "";
  return `reply-comment-exec:${shortHash([
    item?.platform || "",
    replyCommentSourceTargetKey(item),
    commentPersonKey(item),
    commentContentKey({ content: rawComment })
  ].join("|"))}`;
}

function leadReplyCommentExecutionKey(lead) {
  return replyCommentExecutionKey({
    platform: lead?.platform || "",
    sourceTargetUrl: lead?.sourceTargetUrl || lead?.sourceUrl || lead?.pageUrl || lead?.url || "",
    sourceUserId: lead?.sourceUserId || "",
    sourceUserProfileUrl: lead?.sourceUserProfileUrl || "",
    sourceAuthorAlias: lead?.sourceAuthorAlias || lead?.customerName || String(lead?.title || "").split("·")[0].trim(),
    sourceComment: cleanLeadReplyCommentText(lead)
  });
}

function workReplyCommentExecutionKey(work, platform) {
  if (!work?.commentRow) return "";
  return replyCommentExecutionKey({
    platform,
    sourceTargetUrl: work.url || "",
    sourceUserId: work.commentRow.sourceUserId || "",
    sourceUserProfileUrl: work.commentRow.sourceUserProfileUrl || "",
    sourceAuthorAlias: work.commentRow.authorAlias || work.commentAuthor || "",
    sourceComment: work.commentRow.content || work.commentText || ""
  });
}

function replyCommentLeadCompleted(lead) {
  return /已成功|已发送评论|成功转化|已转化/.test([lead?.status, lead?.touchStatus, lead?.lastContactNote].join(" "));
}

function buildCompletedReplyCommentKeys(db, user) {
  const tenantId = tenantIdForUser(user);
  const keys = new Set();
  for (const lead of db.leads || []) {
    if (!canAccessRecord(user, lead) || recordTenantId(lead) !== tenantId) continue;
    if (!cleanLeadReplyCommentText(lead) || !replyCommentLeadCompleted(lead)) continue;
    const key = leadReplyCommentExecutionKey(lead);
    if (key) keys.add(key);
  }
  return keys;
}

function markDuplicateReplyLeadSkipped(db, user, lead, reason) {
  const note = String(reason || "同一评论已有回复记录，已跳过，避免连续重复回复。").replace(/\s+/g, " ").trim();
  lead.status = "已忽略";
  lead.touchStatus = "重复跳过";
  lead.lastContactNote = note;
  lead.updatedAt = now();
  lead.followUps = Array.isArray(lead.followUps) ? lead.followUps : [];
  lead.followUps.unshift({
    id: makeId("follow"),
    actor: user.name || "系统",
    note,
    createdAt: now()
  });
  db.taskRuns = Array.isArray(db.taskRuns) ? db.taskRuns : [];
  db.taskRuns.unshift({
    id: makeId("run"),
    tenantId: recordTenantId(lead),
    tenantName: lead.tenantName || tenantNameForUser(user),
    taskId: lead.id,
    taskName: "评论回复筛重跳过",
    status: "已忽略",
    checked: 1,
    matched: 0,
    detail: `${lead.platform || ""} · ${lead.sourceAuthorAlias || lead.customerName || "评论用户"} · ${cleanLeadReplyCommentText(lead).slice(0, 80)} · ${note}`,
    createdAt: now()
  });
}

function shortHash(value) {
  return crypto.createHash("sha256").update(String(value || "")).digest("hex").slice(0, 24);
}

function normalizeLeadContact(value) {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/[^\da-z_\-\u4e00-\u9fa5]/g, "");
}

function isOfficialLeadRecord(item) {
  const text = [item?.platform, item?.source, item?.assetType, item?.sourceType, item?.sourceName].join(" ");
  return text.includes("留资") || text.includes("表单");
}

function makeLeadDedupeKey(item) {
  const sampleId = item.sampleId || item.sourceSampleId || item.sourceSampleIds?.[0] || "";
  if (/关键字精准回复|评论回复/.test(String([item.source, item.assetType, item.touchStatus].filter(Boolean).join(" ")))) {
    const replyKey = replyCommentExecutionKey({
      platform: item.platform || "",
      sourceTargetUrl: item.sourceTargetUrl || item.sourceUrl || item.pageUrl || item.url || "",
      sourceUserId: item.sourceUserId || "",
      sourceUserProfileUrl: item.sourceUserProfileUrl || "",
      sourceAuthorAlias: item.sourceAuthorAlias || item.authorAlias || item.author || String(item.title || "").split("·")[0].trim(),
      sourceComment: cleanLeadReplyCommentText(item)
    });
    if (replyKey) return replyKey;
  }
  if (isOfficialLeadRecord(item)) {
    const contactKey = normalizeLeadContact(item.platformLeadId)
      || normalizeLeadContact(item.phone)
      || normalizeLeadContact(item.wechat);
    if (contactKey) {
      return `official:${shortHash([
        item.platform || "",
        item.sourceName || item.source || "",
        contactKey
      ].join("|"))}`;
    }
  }
  const titleAuthor = String(item.title || "").split("·")[0] || "";
  const stablePerson = stableCommentPersonKey(item);
  if (stablePerson) {
    return `leadperson:${shortHash([
      item.platform || "",
      stablePerson
    ].join("|"))}`;
  }
  const contentKey = compactFingerprint(item.rawContent || item.content || item.title || "");
  if (!contentKey && sampleId) return `sample:${sampleId}`;
  const personKey = commentPersonKey({
    sourceUserId: item.sourceUserId,
    sourceUserProfileUrl: item.sourceUserProfileUrl,
    authorProfileUrl: item.authorProfileUrl,
    sourceAuthorAlias: item.sourceAuthorAlias,
    authorAlias: item.authorAlias,
    author: item.author || titleAuthor
  });
  const pieces = [
    item.platform || "",
    personKey,
    contentKey
  ];
  return `lead:${shortHash(pieces.join("|"))}`;
}

function intentRank(value) {
  return { "低": 1, "中": 2, "高": 3 }[value] || 0;
}

function mergeLead(existing, incoming, actor, reason = "检测到重复线索，已合并来源。") {
  existing.intent = intentRank(incoming.intent) > intentRank(existing.intent) ? incoming.intent : existing.intent;
  existing.intentTags = uniqueList([...(existing.intentTags || []), ...(incoming.intentTags || [])]);
  existing.intentPrimary = existing.intentPrimary || incoming.intentPrimary || "";
  existing.intentConfidence = Math.max(Number(existing.intentConfidence || 0), Number(incoming.intentConfidence || 0));
	  existing.sourceCandidateIds = uniqueList([...(existing.sourceCandidateIds || []), ...(incoming.sourceCandidateIds || [])]);
	  existing.sourceSampleIds = uniqueList([...(existing.sourceSampleIds || []), ...(incoming.sourceSampleIds || [])]);
	  for (const field of ["customerName", "phone", "wechat", "platformLeadId", "officialSourceConfigId", "sourceName", "sourceScene", "sourceAuthorAlias", "sourceIpLocation", "sourceUserProfileUrl", "sourceUserId", "sourceAvatarUrl", "canPrivateMessage", "followStatus", "touchStatus", "sourceComment", "sourceTargetName", "sourceTargetUrl", "sourceTargetId", "matchedKeyword", "replyKeywordText"]) {
	    if (!existing[field] && incoming[field]) existing[field] = incoming[field];
	  }
  if (!existing.owner && incoming.owner) existing.owner = incoming.owner;
  if (!existing.region && incoming.region) existing.region = incoming.region;
  if (existing.contactPolicy !== "可外联" && incoming.contactPolicy === "可外联") existing.contactPolicy = "可外联";
  existing.updatedAt = now();
  existing.followUps = existing.followUps || [];
  existing.followUps.unshift({
    id: makeId("follow"),
    actor,
    note: `${reason} 新来源：${incoming.title || incoming.source || "未命名来源"}`,
    createdAt: now()
  });
  return existing;
}

function upsertLead(db, lead, actor, mergeReason) {
  ensureRecordTenant(lead);
  lead.dedupeKey = lead.dedupeKey || makeLeadDedupeKey(lead);
  const existing = (db.leads || []).find((item) => recordTenantId(item) === recordTenantId(lead) && item.dedupeKey && item.dedupeKey === lead.dedupeKey);
  if (existing) return { lead: mergeLead(existing, lead, actor, mergeReason), merged: true };
  db.leads.unshift(lead);
  return { lead, merged: false };
}

function replyKeywordTokens(value) {
  return String(value || "")
    .split(/[,，、\s\r\n]+/)
    .map((item) => String(item || "").trim())
    .filter(Boolean)
    .slice(0, 30);
}

function keywordMatchForCommentRow(row, keywordText) {
  const tokens = replyKeywordTokens(keywordText);
  if (!tokens.length) return { matched: true, token: "" };
  const haystack = compactFingerprint(row?.content || "");
  for (const token of tokens) {
    const needle = compactFingerprint(token);
    if (needle && haystack.includes(needle)) return { matched: true, token };
  }
  return { matched: false, token: "" };
}

function normalizeReplyCommentRow(row, platform = "抖音作品/评论") {
  const sourceUserProfileUrl = cleanCommentUserProfileUrl(row?.sourceUserProfileUrl || "");
  return {
    authorAlias: cleanCommentAuthorAlias(row?.authorAlias || ""),
    sourceUserProfileUrl,
    sourceUserId: cleanCommentUserId(row?.sourceUserId || "", sourceUserProfileUrl),
    ipLocation: String(row?.ipLocation || "").trim(),
    content: String(row?.content || "").replace(/\s+/g, " ").trim(),
    platform
  };
}

function importReplyScanRowsToCommentPool(db, context = {}) {
  const user = context.user || {};
  const tenantId = tenantIdForUser(user);
  const platform = String(context.platform || "抖音作品/评论");
  const sourceUrl = String(context.sourceUrl || "");
  const targetName = String(context.targetName || "关键字精准回复全量扫描");
  const rows = (context.rows || []).map((row) => normalizeReplyCommentRow(row, platform)).filter((row) => row.content);
  const matchedRows = (context.matchedRows || []).map((row) => normalizeReplyCommentRow(row, platform)).filter((row) => row.content);
  const matchedKeys = new Set(matchedRows.map((row) => commentDedupeKey({ ...row, platform })).filter(Boolean));
  const targetId = `reply_scan_${shortHash([tenantId, platform, sourceUrl].join("|"))}`;
  const existing = new Map((db.sourceSamples || [])
    .filter((item) => recordTenantId(item) === tenantId)
    .map((item) => [commentDedupeKey(item), item])
    .filter(([key]) => key));
  const samples = [];
  let skipped = 0;
  let updated = 0;
  for (const row of matchedRows) {
    const key = commentDedupeKey({ ...row, platform });
    const existingSample = key ? existing.get(key) : null;
    if (!key || existingSample) {
      if (existingSample && row.ipLocation && !String(existingSample.ipLocation || "").trim()) {
        existingSample.ipLocation = row.ipLocation;
        existingSample.updatedAt = now();
        updated += 1;
      }
      skipped += 1;
      continue;
    }
    const sample = {
      id: makeId("sample"),
      tenantId,
      tenantName: tenantNameForUser(user),
      targetId,
      targetName,
      sourceTargetUrl: sourceUrl,
      platform,
      sourceType: "关键字精准回复命中评论",
      authorAlias: row.authorAlias || "",
      sourceUserId: row.sourceUserId || "",
      sourceUserProfileUrl: row.sourceUserProfileUrl || "",
      region: "",
      ipLocation: row.ipLocation || "",
      content: row.content || "",
      assetType: "互动用户",
      contactPolicy: "需人工确认",
      status: "待识别",
      createdAt: now()
    };
    existing.set(key, sample);
    samples.push(sample);
  }
  db.sourceSamples = Array.isArray(db.sourceSamples) ? db.sourceSamples : [];
  db.sourceSamples.unshift(...samples);
  return { imported: samples.length, skipped, updated, targetId, scanned: rows.length, matched: matchedKeys.size };
}

function upsertCommentReplyResultLead(db, context = {}) {
  const user = context.user || {};
  const account = context.account || {};
  const row = normalizeReplyCommentRow(context.row || {}, context.platform || "抖音作品/评论");
  const work = context.work || {};
  const result = context.result || {};
  const replyText = normalizeReplyText(context.replyText || "");
  const keywordText = String(context.keywordText || "");
  const matchedKeyword = context.matchedKeyword || keywordMatchForCommentRow(row, keywordText).token || "";
  const tenantId = tenantIdForUser(user);
  const tenantName = tenantNameForUser(user);
  const platform = context.platform || row.platform || "抖音作品/评论";
  const sourceTargetUrl = work.url || context.sourceTargetUrl || "";
  const authorAlias = row.authorAlias || "评论用户";
  const sent = Boolean(result.sent);
  const mounted = Boolean(result.mounted);
  const autoSend = context.autoSend === true;
  const mountedLabel = replyMountedStatusLabel(autoSend);
  const status = sent ? "已成功" : "未成功";
  const touchStatus = sent ? "已发送评论" : mounted ? (autoSend ? "已填入未发送" : "已挂载评论") : "未回复成功";
  const reason = String(result.reason || (sent ? "自动回复成功" : mounted ? "已填入回复但未确认发送" : "未完成自动回复")).replace(/\s+/g, " ").trim();
  const actionTrace = Array.isArray(result?.preciseComment?.actionLog)
    ? result.preciseComment.actionLog.filter(Boolean).join(" -> ")
    : "";
  const debugInfo = commentReplyDebugInfo(result);
  const debugSummary = commentReplyDebugSummary(result);
	  const dedupeKey = replyCommentExecutionKey({
	    platform,
	    sourceTargetUrl,
	    sourceUserId: row.sourceUserId || "",
	    sourceUserProfileUrl: row.sourceUserProfileUrl || "",
	    sourceAuthorAlias: authorAlias,
	    sourceComment: row.content || ""
	  }) || `reply-comment:${shortHash([
	    platform,
	    replyWorkIdentityUrl(sourceTargetUrl, platform) || sourceTargetUrl,
	    row.sourceUserId || row.sourceUserProfileUrl || authorAlias,
	    row.content
	  ].join("|"))}`;
  db.leads = Array.isArray(db.leads) ? db.leads : [];
  const existing = db.leads.find((item) => recordTenantId(item) === tenantId && item.dedupeKey === dedupeKey);
  const note = `${sent ? "自动回复成功" : mounted ? `${mountedLabel}，待确认` : "自动回复未成功"}${matchedKeyword ? `；命中关键词：${matchedKeyword}` : ""}${reason ? `；${reason}` : ""}${actionTrace ? `；执行链路：${actionTrace}` : ""}${debugSummary ? `；调试：${debugSummary}` : ""}`;
  const patch = {
    tenantId,
    tenantName,
    title: `${authorAlias} · 评论回复`,
    customerName: authorAlias,
    platform,
    source: "关键字精准回复",
    assetType: "互动用户",
    contactPolicy: "需人工确认",
    region: row.ipLocation || "",
    intent: "",
    intentTags: matchedKeyword ? [matchedKeyword] : [],
    intentPrimary: matchedKeyword || "关键词命中",
    intentConfidence: 0,
    status,
    owner: "",
    content: `命中评论：${row.content || "无内容"}`,
    sourceAuthorAlias: authorAlias,
    sourceIpLocation: row.ipLocation || "",
    sourceUserProfileUrl: row.sourceUserProfileUrl || "",
    sourceUserId: row.sourceUserId || "",
    sourceAvatarUrl: "",
    canPrivateMessage: "",
    followStatus: "未跟进",
    touchStatus,
    sourceComment: row.content || "",
    matchedKeyword,
    replyKeywordText: keywordText,
    sourceTargetName: work.title || context.sourceTargetName || "作品关键词回复",
    sourceTargetUrl,
    sourceTargetId: "",
    replyText,
    replyAccountId: account.id || "",
    replyAccountName: account.accountName || "",
    replyDebug: debugInfo,
    replyDebugUpdatedAt: now(),
    lastContactNote: `${actionTrace ? `${reason}；执行链路：${actionTrace}` : reason}${debugSummary ? `；调试：${debugSummary}` : ""}`,
    lastReplyAt: now(),
    conversionDestination: "",
    suggestion: sent
      ? "已自动回复成功，可在结果复盘中标记成功转化或打开主页继续人工操作。"
      : "已保留未成功原因，可打开来源作品或用户主页进行人工补操作。",
    updatedAt: now()
  };
  if (existing) {
    Object.assign(existing, patch);
    existing.followUps = Array.isArray(existing.followUps) ? existing.followUps : [];
    existing.followUps.unshift({ id: makeId("follow"), actor: user.name || "系统", note, createdAt: now() });
    existing.followUps = existing.followUps.slice(0, 30);
    return { lead: existing, created: false };
  }
  const lead = {
    id: makeId("lead"),
    ...patch,
    dedupeKey,
    createdAt: now(),
    sourceCandidateIds: [],
    sourceSampleIds: [],
    followUps: [{ id: makeId("follow"), actor: user.name || "系统", note, createdAt: now() }]
  };
  db.leads.unshift(lead);
  return { lead, created: true };
}

function mergeDuplicateLeadsByDedupeKey(db, actor = "系统") {
  const kept = [];
  const byKey = new Map();
  let merged = 0;
  for (const lead of db.leads || []) {
    ensureRecordTenant(lead);
    lead.dedupeKey = makeLeadDedupeKey(lead);
    const key = `${recordTenantId(lead)}:${lead.dedupeKey}`;
    const existing = byKey.get(key);
    if (existing) {
      mergeLead(existing, lead, actor, "系统筛重：同一平台用户或同一评论已合并。");
      merged += 1;
    } else {
      byKey.set(key, lead);
      kept.push(lead);
    }
  }
  db.leads = kept;
  return merged;
}

